long strtol(const char *nptr, char **endptr, int base) {
    long r = 0;
    int neg = 0;
    while (isspace(*nptr)) nptr++;
    if (*nptr == '-') { neg = 1; nptr++; }
    else if (*nptr == '+') nptr++;
    if (base == 0) {
        if (*nptr == '0') {
